chart.config_raw:
const ctx = document.getElementById('speedupChart');

    new Chart(ctx, {
      type: 'bar',
      data: {
        labels: [
          'Peak throughput',
          'JSON summarise',
          'LLaVA-Bench',
          'Generative agents',
          'Doc QA'
        ],
        datasets: [{
          data: [6.4, 2.9, 1.7, 1.3, 1.2],
          backgroundColor: ['#4dabf7', '#f6ad55', '#51cf66', '#fab005', '#ff6b6b'],
          borderColor: ['#4dabf7', '#f6ad55', '#51cf66', '#fab005', '#ff6b6b'],
          borderWidth: 1,
          borderRadius: 8,
          barThickness: 18
        }]
      },
      options: {
        animation: false,
        responsive: true,
        maintainAspectRatio: false,
        indexAxis: 'y',
        plugins: {
          legend: {
            display: false
          },
          tooltip: {
            callbacks: {
              label: function(context) {
                return context.raw.toFixed(1) + 'x';
              }
            }
          }
        },
        scales: {
          x: {
            beginAtZero: true,
            suggestedMax: 7,
            grid: {
              color: '#e2e8f0'
            },
            ticks: {
              color: '#4a5568',
              callback: function(value) {
                return value + 'x';
              }
            },
            border: {
              color: '#e2e8f0'
            }
          },
          y: {
            grid: {
              display: false
            },
            ticks: {
              color: '#4a5568',
              font: {
                size: 13
              }
            },
            border: {
              color: '#e2e8f0'
            }
          }
        }
      }
    });
